// src/constants/http-status.ts
var HTTP_STATUS = {
  NOT_FOUND: 404,
  UNAUTHORIZED: 401,
  BAD_REQUEST: 400,
  INTERNAL_SERVER_ERROR: 500,
  FORBIDDEN: 403
};

// src/libs/exception.ts
class HttpError extends Error {
  status;
  constructor(status, message) {
    super(message);
    this.status = status;
    this.name = this.constructor.name;
    throw new HTTPException(status, {
      message: this.message,
      cause: this.stack
    });
  }
}

class NotFoundException extends HttpError {
  constructor(message = "Resource not found") {
    super(HTTP_STATUS.NOT_FOUND, message);
  }
}

class BadRequestException extends HttpError {
  constructor(message = "Bad request") {
    super(HTTP_STATUS.BAD_REQUEST, message);
  }
}

class UnauthorizedException extends HttpError {
  constructor(message = "Unauthorized") {
    super(HTTP_STATUS.UNAUTHORIZED, message);
  }
}

// src/libs/date-helper.ts
class DateHelper {
  static getEpochMs() {
    return new Date().getTime();
  }
}

// src/services/auth.service.ts
class AuthService {
  accountRepository = new AccountRepository;
  async verifySignIn(data) {
    const account = await this.accountRepository.findByEmail(data.email);
    if (!account) {
      throw new BadRequestException(t("error.sign_in_failed"));
    }
    const verifyPassword = await Bun.password.verify(data.password, account.password);
    if (!verifyPassword) {
      throw new BadRequestException(t("error.sign_in_failed"));
    }
    return account;
  }
  async createAccount(data) {
    const checkEmail = await this.accountRepository.existByEmail(data.email);
    if (checkEmail) {
      throw new BadRequestException(t("error.email_already_exist"));
    }
    const encodedPassword = await Bun.password.hash(data.password);
    const profilePicture = generateProfilePicture(data.name);
    const newAccount = {
      email: data.email,
      password: encodedPassword,
      name: data.name,
      profile_picture: profilePicture,
      created_date: DateHelper.getEpochMs(),
      created_by: "SYSTEM"
    };
    await this.accountRepository.save(newAccount);
  }
  async generateToken(payload) {
    const now = Math.floor(Date.now() / 1000);
    const expiresIn = 60 * 60 * 24 * env.JWT_EXPIRES_IN_DAY;
    const jwtPayload = {
      sub: payload.id,
      email: payload.email,
      iat: now,
      exp: now + expiresIn
    };
    return sign2(jwtPayload, env.JWT_SECRET);
  }
  async verifyToken(token) {
    return verify2(token, env.JWT_SECRET, "HS256");
  }
}

// src/services/account.service.ts
class AccountService {
  accountRepository = new AccountRepository;
  async getAccountDataByAccount(account) {
    const data = {
      email: account.email,
      name: account.name,
      id: account.id,
      profile_picture: account.profile_picture
    };
    return data;
  }
  async getAccountDataById(id) {
    const account = await this.accountRepository.findById(id);
    return this.getAccountDataByAccount(account);
  }
}

