// src/repositories/client.repository.ts
class ClientRepository {
  async findAll(accountId, params) {
    const whereClause = and(eq(ClientEntity.account_id, accountId), eq(ClientEntity.active, true), params.q ? or(ilike(ClientEntity.name, `%${params.q}%`)) : undefined);
    const [data, total] = await Promise.all([
      db.select().from(ClientEntity).where(whereClause).limit(params.size).offset(params.page * params.size),
      db.select({ count: count() }).from(ClientEntity).where(whereClause)
    ]);
    return { data, total: total[0].count };
  }
  async findByIdAndAccountId(id, accountId) {
    const data = await db.select().from(ClientEntity).where(and(eq(ClientEntity.id, id), eq(ClientEntity.account_id, accountId), eq(ClientEntity.active, true))).limit(1);
    return data[0];
  }
  async save(client) {
    await db.insert(ClientEntity).values(client);
  }
  async update(id, data) {
    await db.update(ClientEntity).set(data).where(eq(ClientEntity.id, id));
  }
}

